mapper.select:
SELECT c.*, u.user_name FROM tb_comment c LEFT JOIN tb_user u ON u.user_id = c.user_id WHERE c.pdf_id = #{pdfId}
AND c.status = #{status}
ORDER BY c.create_dt DESC

SELECT COALESCE(
    MAX(
        CAST(
            SUBSTRING(comment_code, 3)
            AS UNSIGNED
        )
    ) + 1,
    0
)
FROM tb_comment
WHERE pdf_id = #{pdfId}

SELECT * FROM tb_comment_attachment WHERE comment_id IN
#{commentId}
AND reply_id IS NULL ORDER BY comment_id, create_dt, attachment_id

SELECT * FROM tb_comment_attachment WHERE reply_id IN
#{replyId}
ORDER BY reply_id, create_dt, attachment_id

mapper.update:
UPDATE tb_comment
SET comment_text = #{commentText},
    update_dt = CURRENT_TIMESTAMP
WHERE comment_id = #{commentId}
  AND user_id = #{userId}

UPDATE tb_comment
SET status = #{status},
    update_dt = CURRENT_TIMESTAMP
WHERE comment_id = #{commentId}
  AND user_id = #{userId}

mapper.delete:
DELETE FROM tb_comment_reply
WHERE comment_id = #{commentId}
  AND EXISTS (
      SELECT 1
      FROM tb_comment
      WHERE comment_id = #{commentId}
        AND user_id = #{userId}
  )

DELETE FROM tb_comment
WHERE comment_id = #{commentId}
  AND user_id = #{userId}

mapper.select:
SELECT r.*, u.user_name FROM tb_comment_reply r LEFT JOIN tb_user u ON u.user_id = r.user_id WHERE r.comment_id IN
#{commentId}
ORDER BY r.comment_id, r.create_dt, r.reply_id

mapper.update:
UPDATE tb_comment_reply
SET reply_text = #{replyText}
WHERE reply_id = #{replyId}
  AND user_id = #{userId}

mapper.delete:
DELETE FROM tb_comment_reply
WHERE reply_id = #{replyId}
  AND user_id = #{userId}

mapper.select:
SELECT comment_id
FROM tb_comment_reply
WHERE reply_id = #{replyId}
